package com.google.gson.internal.bind;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.Gson;
import com.google.gson.TypeAdapter;
import com.google.gson.TypeAdapterFactory;
import com.google.gson.reflect.TypeToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class TypeAdaptersTest {

  private Class<BaseClass> baseClass;
  private Class<? extends BaseClass> subClass;
  private TypeAdapter<BaseClass> typeAdapter;
  private TypeAdapterFactory factory;
  private Gson gson;

  static class BaseClass {}
  static class SubClass extends BaseClass {}
  static class OtherClass {}

  @BeforeEach
  void setUp() {
    baseClass = BaseClass.class;
    subClass = SubClass.class;
    typeAdapter = mock(TypeAdapter.class);
    gson = mock(Gson.class);
    factory = TypeAdapters.newFactoryForMultipleTypes(baseClass, subClass, typeAdapter);
  }

  @Test
  void create_whenTypeIsBaseClass_returnsTypeAdapter() {
    TypeToken<BaseClass> typeToken = TypeToken.get(baseClass);
    @SuppressWarnings("unchecked")
    TypeAdapter<BaseClass> adapter = (TypeAdapter<BaseClass>) factory.create(gson, typeToken);
    assertSame(typeAdapter, adapter);
  }

  @Test
  void create_whenTypeIsSubClass_returnsTypeAdapter() {
    TypeToken<SubClass> typeToken = TypeToken.get(subClass);
    @SuppressWarnings("unchecked")
    TypeAdapter<SubClass> adapter = (TypeAdapter<SubClass>) factory.create(gson, typeToken);
    assertSame(typeAdapter, adapter);
  }

  @Test
  void create_whenTypeIsOtherClass_returnsNull() {
    TypeToken<OtherClass> typeToken = TypeToken.get(OtherClass.class);
    TypeAdapter<OtherClass> adapter = factory.create(gson, typeToken);
    assertNull(adapter);
  }

  @Test
  void toString_containsBaseAndSubClassNamesAndAdapter() {
    String toString = factory.toString();
    assertTrue(toString.contains(baseClass.getName()));
    assertTrue(toString.contains(subClass.getName()));
    assertTrue(toString.contains(typeAdapter.toString()));
  }
}
